import{_ as r,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"步人甲","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/3.防具/2.D级/步人甲.md","filePath":"4.资源分区/7.物品与装备/3.防具/2.D级/步人甲.md"}'),d={name:"4.资源分区/7.物品与装备/3.防具/2.D级/步人甲.md"};function p(l,a,_,i,c,h){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"步人甲",tabindex:"-1"},[s("步人甲 "),e("a",{class:"header-anchor",href:"#步人甲","aria-label":'Permalink to "步人甲"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：勿忘尘003C")])])],-1),o('<h1 id="步人甲-1" tabindex="-1">步人甲 <a class="header-anchor" href="#步人甲-1" aria-label="Permalink to &quot;步人甲&quot;">​</a></h1><p>步人甲<br> D+500<br> 科技本质<br> 步人甲由1825枚甲叶组成，一般重量达58宋斤（1宋斤等于1.2市斤）以上，同时可通过增加甲叶数量来提高防护力，但是重量会进一步上升。为此到后来皇帝亲自赐命，规定步兵铠甲以58宋斤为限。同时期的欧洲步骑兵的铠甲类型还以锁子甲为主，防护性及重量均不如步人甲。<br> 这是一件重盔甲 护甲为1/1 具有全封闭3 盔甲减值2</p><p>【沉重】沉重的盔甲带来不俗的防御同时，也让穿戴者的负重情况更加的恶劣，这有好有坏，此时穿戴者在冲撞/摔绊/击飞的对抗中获得获得2dp加值</p><p>【增加甲叶】步人甲使用了可以添加甲叶来提高防御的技术，此时，在步人甲的拥有者可以支付500分购买新的增加甲叶 新的甲叶能够让步人甲的护甲防御提升2/2 ，盔甲减值1；可重复购买至多2次</p><hr><p>Copyright ? 2023 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',6)])])}const m=r(d,[["render",p]]);export{f as __pageData,m as default};
